#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int marks;
        scanf("%d", &marks);
        if (marks >= 90) printf("A\n");
        else if (marks >= 70) printf("B\n");
        else if (marks >= 50) printf("C\n");
        else printf("D\n");
    }
    return 0;
}

