import sys
data = sys.stdin.read().strip().split()
if not data:
    sys.exit()
T = int(data[0])
out = []
idx = 1
for _ in range(T):
    marks = int(data[idx])
    idx += 1
    if marks >= 90:
        out.append('A')
    elif marks >= 70:
        out.append('B')
    elif marks >= 50:
        out.append('C')
    else:
        out.append('D')
print('\n'.join(out))

